package com.sme.erp.accounting.controller; import com.sme.erp.accounting.entity.YearEndClosing; import com.sme.erp.accounting.service.YearEndClosingService; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/v1/accounting/year-end-closings") public class YearEndClosingController {private final YearEndClosingService service;public YearEndClosingController(YearEndClosingService s){service=s;}@GetMapping @PreAuthorize("hasAuthority('YEAR_END_VIEW')") public List<YearEndClosing> all(){return service.all();}@PostMapping("/prepare") @PreAuthorize("hasAuthority('YEAR_END_PREPARE')") public YearEndClosing prepare(@RequestParam Integer fiscalYear){return service.prepare(fiscalYear);}@PostMapping("/{id}/complete") @PreAuthorize("hasAuthority('YEAR_END_COMPLETE')") public YearEndClosing complete(@PathVariable Long id){return service.complete(id);}}
